arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_a1a0c7425ad9409e961efc5843c003d8.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1 class="apply-title">Job Application</h1>

    @if (!_submitted)
    {
        <!-- Step Indicator Bar -->
        <nav class="step-indicator" aria-label="Application steps">
            @for (int i = 0; i < _stepLabels.Length; i++)
            {
                var stepIndex = i;
                var status = stepIndex < _currentStep ? "completed"
                           : stepIndex == _currentStep ? "active"
                           : "upcoming";
                <button class="step-item @status"
                        disabled="@(status == "upcoming")"
                        @onclick="() => GoToStep(stepIndex)"
                        aria-current="@(status == "active" ? "step" : null)">
                    <span class="step-circle">
                        @if (status == "completed")
                        {
                            <span class="step-check">✓</span>
                        }
                        else
                        {
                            @(stepIndex + 1)
                        }
                    </span>
                    <span class="step-label">@_stepLabels[stepIndex]</span>
                </button>
                @if (stepIndex < _stepLabels.Length - 1)
                {
                    <div class="step-connector @(stepIndex < _currentStep ? "completed" : "")"></div>
                }
            }
        </nav>

        @if (!string.IsNullOrEmpty(_errorMessage))
        {
            <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
        }

        <!-- Step 1: Personal Info -->
        @if (_currentStep == 0)
        {
            <section class="step-content">
                <h2>Personal Information</h2>
                <div class="form-group">
                    <label for="fullName">Full Name <span class="required">*</span></label>
                    <input id="fullName" type="text" class="form-control" @bind="_fullName" placeholder="Enter your full name" />
                </div>
                <div class="form-group">
                    <label for="email">Email <span class="required">*</span></label>
                    <input id="email" type="email" class="form-control" @bind="_email" placeholder="you@example.com" />
                </div>
                <div class="form-group">
                    <label for="phone">Phone <span class="required">*</span></label>
                    <input id="phone" type="tel" class="form-control" @bind="_phone" placeholder="(555) 123-4567" />
                </div>
                <div class="form-group">
                    <label for="address">Address <span class="required">*</span></label>
                    <textarea id="address" class="form-control" @bind="_address" rows="2" placeholder="Street, City, State, ZIP"></textarea>
                </div>
                <div class="step-buttons">
                    <span></span>
                    <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                        @if (_isValidating)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                            <span>Validating…</span>
                        }
                        else
                        {
                            <span>Next →</span>
                        }
                    </button>
                </div>
            </section>
        }

        <!-- Step 2: Work History -->
        @if (_currentStep == 1)
        {
            <section class="step-content">
