                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                            }
                        </div>
                        <div class="form-row">
                            <div class="form-group flex-1">
                                <label>Name <span class="required">*</span></label>
                                <input type="text" class="form-control" @bind="_references[idx].Name" placeholder="Reference name" />
                            </div>
                            <div class="form-group flex-1">
                                <label>Relationship <span class="required">*</span></label>
                                <input type="text" class="form-control" @bind="_references[idx].Relationship" placeholder="e.g., Former Manager" />
                            </div>
                        </div>
                        <div class="form-row">
                            <div class="form-group flex-1">
                                <label>Email <span class="required">*</span></label>
                                <input type="email" class="form-control" @bind="_references[idx].Email" placeholder="reference@example.com" />
