.apply-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 1rem 0 3rem;
}

.apply-title {
    text-align: center;
    margin-bottom: 2rem;
    font-weight: 700;
}

/* Step Indicator */
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    gap: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
    transition: opacity 0.2s;
    min-width: 90px;
}

.step-item.upcoming {
    opacity: 0.4;
    cursor: default;
}

.step-item.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
